from flask import Flask, render_template, redirect, url_for, request, abort
import os
from datetime import datetime

app = Flask(__name__)

# Data file paths
SONGS_FILE = 'data/songs.txt'
ARTISTS_FILE = 'data/artists.txt'
ALBUMS_FILE = 'data/albums.txt'
GENRES_FILE = 'data/genres.txt'
PLAYLISTS_FILE = 'data/playlists.txt'
PLAYLIST_SONGS_FILE = 'data/playlist_songs.txt'

# Helper functions to read data from files

def read_songs():
    songs = []
    if not os.path.exists(SONGS_FILE):
        return songs
    with open(SONGS_FILE, 'r', encoding='utf-8') as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            parts = line.split('|')
            if len(parts) != 8:
                continue
            try:
                song_id = int(parts[0])
                title = parts[1]
                artist_id = int(parts[2])
                album_id = int(parts[3])
                genre = parts[4]
                duration = int(parts[5])
                release_date = parts[6]
                play_count = int(parts[7])
                songs.append({
                    'song_id': song_id,
                    'title': title,
                    'artist_id': artist_id,
                    'album_id': album_id,
                    'genre': genre,
                    'duration': duration,
                    'release_date': release_date,
                    'play_count': play_count
                })
            except Exception:
                continue
    return songs

def read_artists():
    artists = []
    if not os.path.exists(ARTISTS_FILE):
        return artists
    with open(ARTISTS_FILE, 'r', encoding='utf-8') as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            parts = line.split('|')
            if len(parts) != 5:
                continue
            try:
                artist_id = int(parts[0])
                name = parts[1]
                genre = parts[2]
                country = parts[3]
                formation_year = int(parts[4])
                artists.append({
                    'artist_id': artist_id,
                    'name': name,
                    'genre': genre,
                    'country': country,
                    'formation_year': formation_year
                })
            except Exception:
                continue
    return artists

def read_albums():
    albums = []
    if not os.path.exists(ALBUMS_FILE):
        return albums
    with open(ALBUMS_FILE, 'r', encoding='utf-8') as f:
        for line in f:
            line = line.strip()
            if not line:
                continue
            parts = line.split('|')
            if len(parts) != 6:
                continue
            try:
                album_id = int(parts[0])
                title = parts[1]
