        except Exception:
            continue
    return reviews


def save_reviews(reviews):
    rows = []
    for rv in reviews:
        rows.append([
            rv['review_id'],
            rv['book_id'],
            rv['customer_name'],
            rv['rating'],
            rv['review_text'],
            rv['review_date']
        ])
    write_pipe_delimited_file(os.path.join(DATA_DIR, 'reviews.txt'), rows)


def get_bestsellers():
    # Fields: book_id|sales_count|period
    raw = read_pipe_delimited_file(os.path.join(DATA_DIR, 'bestsellers.txt'), 3)
    bestsellers = []
    for r in raw:
        try:
            b = {
                'book_id': int(r[0]),
                'sales_count': int(r[1]),
                'period': r[2]
            }
            bestsellers.append(b)
        except Exception:
            continue
    return bestsellers


