from flask import Flask, render_template, redirect, url_for, request
import os

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

DATA_DIR = 'data'


# Utility functions to load data from files

def load_current_weather():
    filename = os.path.join(DATA_DIR, 'current_weather.txt')
    data = {}
    try:
        with open(filename, 'r', encoding='utf-8') as f:
            for line in f:
                fields = line.strip().split('|')
                if len(fields) != 7:
                    continue
                location_id = int(fields[0])
                data[location_id] = {
                    'location_id': location_id,
                    'location_name': fields[1],
                    'temperature': float(fields[2]),
                    'condition': fields[3],
                    'humidity': int(fields[4]),
                    'wind_speed': float(fields[5]),
                    'last_updated': fields[6]
                }
    except (IOError, ValueError):
        pass
    return data


def load_forecasts():
    filename = os.path.join(DATA_DIR, 'forecasts.txt')
    data = []
    try:
        with open(filename, 'r', encoding='utf-8') as f:
            for line in f:
                fields = line.strip().split('|')
                if len(fields) != 8:
                    continue
                try:
                    forecast_id = int(fields[0])
                    location_id = int(fields[1])
                    forecast = {
                        'forecast_id': forecast_id,
                        'location_id': location_id,
                        'date': fields[2],
                        'high_temp': float(fields[3]),
                        'low_temp': float(fields[4]),
                        'condition': fields[5],
                        'precipitation': int(fields[6]),
                        'humidity': int(fields[7])
                    }
                    data.append(forecast)
                except ValueError:
                    continue
    except IOError:
        pass
    return data


def load_locations():
    filename = os.path.join(DATA_DIR, 'locations.txt')
    data = {}
    try:
        with open(filename, 'r', encoding='utf-8') as f:
            for line in f:
                fields = line.strip().split('|')
                if len(fields) != 6:
                    continue
                try:
                    location_id = int(fields[0])
                    data[location_id] = {
                        'location_id': location_id,
                        'location_name': fields[1],
                        'latitude': float(fields[2]),
                        'longitude': float(fields[3]),
                        'country': fields[4],
                        'timezone': fields[5]
                    }
                except ValueError:
                    continue
    except IOError:
        pass
    return data


def load_alerts():
    filename = os.path.join(DATA_DIR, 'alerts.txt')
    data = []
    try:
        with open(filename, 'r', encoding='utf-8') as f:
            for line in f:
                fields = line.strip().split('|')
                if len(fields) != 8:
                    continue
                try:
                    alert_id = int(fields[0])
                    location_id = int(fields[1])
                    is_acknowledged = bool(int(fields[7]))
                    alert = {
                        'alert_id': alert_id,
                        'location_id': location_id,
                        'alert_type': fields[2],
                        'severity': fields[3],
                        'description': fields[4],
                        'start_time': fields[5],
                        'end_time': fields[6],
                        'is_acknowledged': is_acknowledged
                    }
                    data.append(alert)
                except ValueError:
                    continue
    except IOError:
        pass
    return data


def load_air_quality():
    filename = os.path.join(DATA_DIR, 'air_quality.txt')
    data = {}
    try:
        with open(filename, 'r', encoding='utf-8') as f:
            for line in f:
                fields = line.strip().split('|')
                if len(fields) != 8:
                    continue
                try:
                    aqi_id = int(fields[0])  # unused directly but mandatory parse
                    location_id = int(fields[1])
                    data[location_id] = {
                        'aqi_index': int(fields[2]),
                        'pm25': float(fields[3]),
